SELECT id,path,name,city FROM stores WHERE city='Graz' AND name LIKE '%Jakomini%' LIMIT 1;
SELECT i.sku,i.available_today,p.path
FROM inventory i JOIN products p ON p.sku=i.sku
WHERE i.store_id=(SELECT id FROM stores WHERE city='Graz' AND name LIKE '%Jakomini%' LIMIT 1)
  AND i.sku IN ('HND-2FFOGA9T','ADH-2U8ETNHK','SFE-3JK7H31T','MAC-2JV5BGPP','AUT-160WP2PB','ELC-1ECVU00O')
ORDER BY i.sku;
